sys_ui_action.script:
current.setValue("state", "3");
current.update();

var grMedia = new GlideRecord("x_153878_netflix_media");
grMedia.addEncodedQuery("title=" + current.getValue("title") + "^type=" + current.getValue("type") + "^release_year=" + current.getValue("release_year") + "^sys_id!=" + current.getValue("sys_id"));
grMedia.query();

while (grMedia.next()) {
    grMedia.setValue("state", "2");
    grMedia.setValue("genre", "");
    grMedia.setValue("release_date", "");
    grMedia.setValue("release_year", "");
    grMedia.setValue("category", "");
    grMedia.setValue("synopsis", "");
    grMedia.setValue("writers", "");
    grMedia.setValue("production", "");
    grMedia.setValue("poster", "");
    grMedia.setValue("website", "");
    grMedia.setValue("average_rating", "");
    grMedia.setValue("imdb_rating", "");
    grMedia.setValue("metascore", "");
    grMedia.setValue("awards", "");
    grMedia.setValue("language", "");
    grMedia.setValue("country", "");
    grMedia.setValue("integration_state", "3");
    grMedia.setValue("integration_error_message", "");

    var grMediaActor = new GlideRecord("x_153878_netflix_m2m_actors_medias");
    grMediaActor.addEncodedQuery("x_153878_netflix_media=" + grMedia.getValue("sys_id"));
    grMediaActor.query();
    grMediaActor.deleteMultiple();

    var grMediaDirector = new GlideRecord("x_153878_netflix_m2m_directors_medias");
    grMediaDirector.addEncodedQuery("x_153878_netflix_media=" + grMedia.getValue("sys_id"));
    grMediaDirector.query();
    grMediaDirector.deleteMultiple();

    grMedia.update();
}

action.setRedirectURL(current);
